import java.util.Scanner;

public class DemoIncrement 
{

	public static void main(String[] args) 
	{
		// TODO Auto-generated method stub
		
		//variables
		int v = 4;
		int plusPlusV = ++v;
		
		System.out.println("v is " + v);
		System.out.println("++v is" + plusPlusV);
		System.out.println("v++ is" + plusPlusV);
	}
}